import React from 'react';

const GlicoLogo = ({ size = 'medium', className = '' }) => {
  const sizeClasses = {
    small: 'h-8',
    medium: 'h-12',
    large: 'h-16'
  };

  return (
    <div className={`flex items-center ${sizeClasses[size]} ${className}`}>
      <img 
        src="/Glico_logo.png" 
        alt="GLICO LIFE" 
        className={`h-full object-contain`}
      />
    </div>
  );
};

export default GlicoLogo;
